print(f"{(opcao := int(input('Insira a opção (1 - Ordem crescente, 2 - Ordem decrescente, 3 - Maior valor entre os outros 2): '))) and ''}{(a := float(input('Insira o valor de a: '))) and ''}{(b := float(input('Insira o valor de b: '))) and ''}{(c := float(input('Insira o valor de c: '))) and ''}{(f'Os valores em ordem crescente são: {a}, {b} e {c}.' if opcao == 1 else (f'Os valores em ordem decrescente são: {a}, {b} e {c}.' if opcao == 2 else f'Os valores com o maior valor entre os outros 2 são: {a}, {b} e {c}.' if opcao == 3 else 'Opção inválida.'))}")
